+      *C == -(*UmaxC)) {
+    Value *UmaxCVal = ConstantInt::get(Ty, *UmaxC);
+    return replaceInstUsesWith(
+        Add, Builder.CreateIntrinsic(Intrinsic::usub_sat, {Ty}, {XVal, UmaxCVal}));
+  }
